mapper.select:
SELECT slot, count(*) AS cnt FROM ( SELECT CASE WHEN extract(hour from ci.check_in) < 6 THEN '새벽(00-06)' WHEN extract(hour from ci.check_in) < 11 THEN '오전(06-11)' WHEN extract(hour from ci.check_in) < 14 THEN '점심(11-14)' WHEN extract(hour from ci.check_in) < 18 THEN '오후(14-18)' WHEN extract(hour from ci.check_in) < 22 THEN '저녁(18-22)' ELSE '야간(22-24)' END AS slot FROM "h_check_inout" ci WHERE ci.gym_id = #{gymId}
AND to_char(ci.check_in, 'YYYY-MM') = #{period}
AND ci.check_in >= cast(#{period} as date) - interval '30 days' AND ci.check_in <= cast(#{period} as date) + interval '1 day'
AND ci.username IN ( SELECT distinct r.username FROM "h_churn_result" r JOIN "h_member" m ON r.username = m.username WHERE m.gym_id = #{gymId} AND r.churn_rate >= 0.45 AND #{statKey} IN (r.top1_reason, r.top2_reason, r.top3_reason)
AND r.churn_date IS NOT NULL AND to_char(r.churn_date, 'YYYY-MM') = #{period}
AND r.churn_date = cast(#{period} as date)
) ) t GROUP BY slot ORDER BY cnt DESC
